import { heapify, heappop } from 'heap-js';

function solve(value, limit) {
    const n = value.length;
    // Use a priority queue to always activate the element with the highest value
    // We will store tuples of (-value[i], limit[i]) to simulate a max-heap
    const heap = [[-value[i], limit[i]] for (let i = 0; i < n; i++)];
    heapify(heap);

    let activeCount = 0;
    let totalSum = 0;
    const inactiveSet = new Set();

    while (heap.length > 0) {
        const [val, lim] = heappop(heap);
        const actualVal = -val;

        // Check if the element can be activated
        if (activeCount < lim && !inactiveSet.has(lim)) {
            // Activate the element
            totalSum += actualVal;
            activeCount += 1;

            // After activation, check which elements become inactive
            for (let i = 0; i < n; i++) {
                if (!inactiveSet.has(i) && limit[i] <= activeCount) {
                    inactiveSet.add(i);
                }
            }
        }
    }

    return totalSum;
}
